insert into public.listings (id, title, description, category, images, city, region, address, lat, lng, price, price_unit, rating, review_count, amenities, max_vehicle_length, spots, tags, host_name, host_avatar, host_response_rate, host_response_time, host_joined_year, host_listings_count) values
('p1', 'Sentrum Pendlerparkering', 'Trygg og beleilig parkeringsplass rett ved Oslo S. Perfekt for pendlere som trenger daglig parkering i sentrum. Døgnåpen tilgang med elektrisk port og overvåkningskameraer. Kort gangavstand til kollektivtransport.', 'parking', '{"https://images.unsplash.com/photo-1590674899484-d5640e854abe?w=800&h=600&fit=crop","https://images.unsplash.com/photo-1573348722427-f1d6819fdf98?w=800&h=600&fit=crop","https://images.unsplash.com/photo-1506521781263-d8422e82f27a?w=800&h=600&fit=crop"}', 'Oslo', 'Oslo', 'Schweigaards gate 14', 59.9107, 10.7592, 150, 'time', 4.8, 124, '{"covered","security_camera","gated","ev_charging","lighting"}', null, 12, '{"popular","featured"}', 'Erik Hansen', 'https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?w=100&h=100&fit=crop&facepad=2', 98, 'innen 1 time', 2022, 3),
('p2', 'Garasje ved Bryggen', 'Privat garasjeplass i hjertet av Bergen, kun minutter fra Bryggen og Fisketorget. Overbygget og beskyttet mot regn. Ideell for turister og forretningsreisende.', 'parking', '{"https://images.unsplash.com/photo-1506521781263-d8422e82f27a?w=800&h=600&fit=crop","https://images.unsplash.com/photo-1573348722427-f1d6819fdf98?w=800&h=600&fit=crop"}', 'Bergen', 'Vestland', 'Strandgaten 22', 60.3943, 5.3259, 120, 'time', 4.6, 87, '{"covered","security_camera","lighting"}', null, 4, '{"available_today"}', 'Ingrid Larsen', 'https://images.unsplash.com/photo-1438761681033-6461ffad8d80?w=100&h=100&fit=crop&facepad=2', 95, 'innen 2 timer', 2023, 1),
('p3', 'EV-parkering Solsiden', 'Moderne parkeringsanlegg med hurtiglading for elbiler. Sentralt plassert i Trondheims mest populære bydel. Tilgang via app eller kort.', 'parking', '{"https://images.unsplash.com/photo-1506521781263-d8422e82f27a?w=800&h=600&fit=crop","https://images.unsplash.com/photo-1593941707882-a5bba14938c7?w=800&h=600&fit=crop"}', 'Trondheim', 'Trøndelag', 'Beddingen 10', 63.4337, 10.4108, 180, 'time', 4.9, 56, '{"ev_charging","covered","gated","security_camera","lighting"}', null, 8, '{"featured","available_today"}', 'Olav Moen', 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=100&h=100&fit=crop&facepad=2', 100, 'innen 30 min', 2021, 5),
('p4', 'Flyplass Langtidsparkering', 'Rimelig langtidsparkering nær Stavanger lufthavn Sola. Gratis shuttle til terminalen hver 15. minutt. Trygt område med gjerde og kameraovervåkning.', 'parking', '{"https://images.unsplash.com/photo-1573348722427-f1d6819fdf98?w=800&h=600&fit=crop","https://images.unsplash.com/photo-1590674899484-d5640e854abe?w=800&h=600&fit=crop"}', 'Stavanger', 'Rogaland', 'Flyplassveien 230', 58.882, 5.638, 89, 'time', 4.4, 203, '{"gated","security_camera","lighting"}', null, 30, '{"popular"}', 'Kari Nilsen', 'https://images.unsplash.com/photo-1544005313-94ddf0286df2?w=100&h=100&fit=crop&facepad=2', 92, 'innen 3 timer', 2023, 2),
('p5', 'Privat Oppkjørsel Majorstuen', 'Rolig og trygg parkeringsplass på privat oppkjørsel i attraktivt boligområde. Kort vei til T-bane og butikker. Perfekt for de som jobber i Oslo vest.', 'parking', '{"https://images.unsplash.com/photo-1486006920555-c77dcf18193c?w=800&h=600&fit=crop","https://images.unsplash.com/photo-1590674899484-d5640e854abe?w=800&h=600&fit=crop"}', 'Oslo', 'Oslo', 'Sorgenfrigata 8', 59.9296, 10.7136, 100, 'time', 4.7, 42, '{"lighting"}', null, 2, '{"available_today"}', 'Anders Berg', 'https://images.unsplash.com/photo-1500648767791-00dcc994a43e?w=100&h=100&fit=crop&facepad=2', 88, 'innen 4 timer', 2024, 1),
('c1', 'Fjordcamp Hardanger', 'Vakker bobilplass rett ved Hardangerfjorden med fantastisk utsikt. Moderne fasiliteter inkludert dusj, toalett og strømtilkobling. Perfekt utgangspunkt for fjordcruise og fruktgårder.', 'camping', '{"https://images.unsplash.com/photo-1504280390367-361c6d9f38f4?w=800&h=600&fit=crop","https://images.unsplash.com/photo-1478827536114-da961b7f86d2?w=800&h=600&fit=crop","https://images.unsplash.com/photo-1523987355523-c7b5b0dd90a7?w=800&h=600&fit=crop"}', 'Ulvik', 'Vestland', 'Fjordveien 45', 60.5682, 6.9103, 350, 'natt', 4.9, 178, '{"electricity","water","toilets","showers","wifi","waste_disposal","lake_access","pets_allowed"}', 10, 15, '{"popular","available_today"}', 'Siri Fjordheim', 'https://images.unsplash.com/photo-1494790108377-be9c29b29330?w=100&h=100&fit=crop&facepad=2', 99, 'innen 1 time', 2021, 2),
('c2', 'Lofoten Utsiktsplass', 'Spektakulær bobilparkering med panoramautsikt over Lofotens ikoniske fjelltopper og fiskevær. Enkel men sjarmerende plass med grunnleggende fasiliteter. Midnattssol om sommeren!', 'camping', '{"https://images.unsplash.com/photo-1520250497591-112f2f40a3f4?w=800&h=600&fit=crop","https://images.unsplash.com/photo-1476514525535-07fb3b4ae5f1?w=800&h=600&fit=crop","https://images.unsplash.com/photo-1504280390367-361c6d9f38f4?w=800&h=600&fit=crop"}', 'Reine', 'Nordland', 'Reinebringen 2', 67.9324, 13.0884, 420, 'natt', 4.8, 93, '{"toilets","water","waste_disposal","mountain_view","pets_allowed"}', 8, 6, '{"featured"}', 'Magnus Nordland', 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=100&h=100&fit=crop&facepad=2', 94, 'innen 2 timer', 2022, 3),
('c3', 'Skogsplass ved Mjøsa', 'Fredelig skogsplass ved Norges største innsjø. Bålplass, fiskemuligheter og turløyper rett utenfor døren. Familievennlig med lekeplass. Strøm og vann tilgjengelig.', 'camping', '{"https://images.unsplash.com/photo-1510312305653-8ed496efae75?w=800&h=600&fit=crop","https://images.unsplash.com/photo-1504280390367-361c6d9f38f4?w=800&h=600&fit=crop","https://images.unsplash.com/photo-1478827536114-da961b7f86d2?w=800&h=600&fit=crop"}', 'Hamar', 'Innlandet', 'Strandvegen 100', 60.7945, 11.068, 280, 'natt', 4.7, 65, '{"electricity","water","toilets","campfire","lake_access","pets_allowed","waste_disposal"}', 12, 20, '{"available_today"}', 'Liv Hamar', 'https://images.unsplash.com/photo-1580489944761-15a19d654956?w=100&h=100&fit=crop&facepad=2', 97, 'innen 1 time', 2022, 1),
('c4', 'Geiranger Fjordcamping', 'UNESCO-verdensarvsted! Bobilplass med direkte utsikt til Geirangerfjorden og De syv søstre. Full service camping med butikk, restaurant og utleie av kajakk.', 'camping', '{"https://images.unsplash.com/photo-1523987355523-c7b5b0dd90a7?w=800&h=600&fit=crop","https://images.unsplash.com/photo-1476514525535-07fb3b4ae5f1?w=800&h=600&fit=crop","https://images.unsplash.com/photo-1510312305653-8ed496efae75?w=800&h=600&fit=crop"}', 'Geiranger', 'Møre og Romsdal', 'Fjordvegen 1', 62.1008, 7.2059, 450, 'natt', 4.9, 312, '{"electricity","water","toilets","showers","wifi","waste_disposal","mountain_view","lake_access"}', 15, 40, '{"popular","featured"}', 'Bjørn Geiranger', 'https://images.unsplash.com/photo-1506794778202-cad84cf45f1d?w=100&h=100&fit=crop&facepad=2', 100, 'innen 30 min', 2020, 4),
('c5', 'Nordkapp Villmarksplass', 'Nordligste bobilparkering i Europa! Opplev midnattssol og nordlys fra denne unike plassen nær Nordkapp. Enkel standard, men en uforglemmelig opplevelse.', 'camping', '{"https://images.unsplash.com/photo-1520250497591-112f2f40a3f4?w=800&h=600&fit=crop","https://images.unsplash.com/photo-1504280390367-361c6d9f38f4?w=800&h=600&fit=crop"}', 'Honningsvåg', 'Troms og Finnmark', 'Nordkapveien 1', 71.1685, 25.7838, 380, 'natt', 4.6, 147, '{"toilets","water","electricity","waste_disposal","mountain_view"}', 10, 10, '{"featured"}', 'Tone Nordkapp', 'https://images.unsplash.com/photo-1534528741775-53994a69daeb?w=100&h=100&fit=crop&facepad=2', 90, 'innen 3 timer', 2023, 1),
('p6', 'Aker Brygge Parkeringshus', 'Moderne parkeringshus ved Oslos mest populære havnepromenade. Perfekt for shopping, restaurantbesøk eller kontorarbeid i området. Godt opplyst og trygt.', 'parking', '{"https://images.unsplash.com/photo-1573348722427-f1d6819fdf98?w=800&h=600&fit=crop","https://images.unsplash.com/photo-1506521781263-d8422e82f27a?w=800&h=600&fit=crop"}', 'Oslo', 'Oslo', 'Brynjulf Bulls plass 2', 59.9087, 10.7267, 200, 'time', 4.7, 189, '{"covered","security_camera","gated","ev_charging","lighting"}', null, 50, '{"popular","available_today"}', 'Henrik Strand', 'https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?w=100&h=100&fit=crop&facepad=2', 96, 'innen 1 time', 2021, 4),
('p7', 'Bodø Sentrum Parkering', 'Sentral parkeringsplass i Bodø, ideell for reisende som tar Hurtigruten eller utforsker Saltstraumen. Kort vei til butikker og restauranter.', 'parking', '{"https://images.unsplash.com/photo-1486006920555-c77dcf18193c?w=800&h=600&fit=crop","https://images.unsplash.com/photo-1590674899484-d5640e854abe?w=800&h=600&fit=crop"}', 'Bodø', 'Nordland', 'Sjøgata 3', 67.2804, 14.4049, 95, 'time', 4.5, 34, '{"lighting","security_camera"}', null, 8, '{"featured"}', 'Marte Nordvik', 'https://images.unsplash.com/photo-1494790108377-be9c29b29330?w=100&h=100&fit=crop&facepad=2', 91, 'innen 2 timer', 2024, 1),
('p8', 'Fredrikstad Gamlebyen P-plass', 'Parkering ved vakre Gamlebyen i Fredrikstad. Utforsk Norges best bevarte festningsby til fots. Rolig og trygt område.', 'parking', '{"https://images.unsplash.com/photo-1590674899484-d5640e854abe?w=800&h=600&fit=crop","https://images.unsplash.com/photo-1573348722427-f1d6819fdf98?w=800&h=600&fit=crop"}', 'Fredrikstad', 'Østfold', 'Gamlebyveien 1', 59.2181, 10.9298, 75, 'time', 4.3, 28, '{"lighting"}', null, 6, '{"available_today"}', 'Thomas Enger', 'https://images.unsplash.com/photo-1500648767791-00dcc994a43e?w=100&h=100&fit=crop&facepad=2', 85, 'innen 4 timer', 2024, 1),
('c6', 'Trolltunga Basecamp', 'Bobilparkering ved foten av den berømte Trolltunga-turen. Våkn opp til fjellutsikt og start turen rett fra plassen. Grunnleggende fasiliteter med fokus på naturnærhet.', 'camping', '{"https://images.unsplash.com/photo-1504280390367-361c6d9f38f4?w=800&h=600&fit=crop","https://images.unsplash.com/photo-1510312305653-8ed496efae75?w=800&h=600&fit=crop"}', 'Odda', 'Vestland', 'Trolltungavegen 89', 60.1241, 6.5449, 320, 'natt', 4.8, 256, '{"toilets","water","waste_disposal","mountain_view","campfire"}', 9, 12, '{"popular","featured"}', 'Eirik Fjellstad', 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=100&h=100&fit=crop&facepad=2', 97, 'innen 1 time', 2021, 2),
('c7', 'Preikestolen Camping', 'Campingplass med utsikt over Lysefjorden, kun kort kjøretur fra Preikestolen. Moderne fasiliteter og familievennlig atmosfære. Kajakk- og fiskeutleie tilgjengelig.', 'camping', '{"https://images.unsplash.com/photo-1523987355523-c7b5b0dd90a7?w=800&h=600&fit=crop","https://images.unsplash.com/photo-1478827536114-da961b7f86d2?w=800&h=600&fit=crop"}', 'Jørpeland', 'Rogaland', 'Preikestolvegen 40', 58.9865, 6.1867, 390, 'natt', 4.7, 142, '{"electricity","water","toilets","showers","wifi","lake_access","mountain_view","pets_allowed"}', 12, 25, '{"popular","available_today"}', 'Silje Lyse', 'https://images.unsplash.com/photo-1580489944761-15a19d654956?w=100&h=100&fit=crop&facepad=2', 98, 'innen 30 min', 2022, 1),
('c8', 'Lyngør Skjærgårdscamping', 'Idyllisk camping ved Sørlandets fineste skjærgård. Bobilplass med sjøutsikt, bademuligheter og kort vei til Lyngør — kåret til Europas best bevarte tettsted.', 'camping', '{"https://images.unsplash.com/photo-1476514525535-07fb3b4ae5f1?w=800&h=600&fit=crop","https://images.unsplash.com/photo-1520250497591-112f2f40a3f4?w=800&h=600&fit=crop"}', 'Tvedestrand', 'Agder', 'Lyngørveien 15', 58.6339, 9.1429, 310, 'natt', 4.9, 87, '{"electricity","water","toilets","showers","lake_access","pets_allowed","waste_disposal"}', 8, 10, '{"featured","available_today"}', 'Anne Skjærgård', 'https://images.unsplash.com/photo-1438761681033-6461ffad8d80?w=100&h=100&fit=crop&facepad=2', 100, 'innen 1 time', 2023, 1),
('p9', 'Tromsø Havn Parkering', 'Parkeringsplass ved Tromsø havn med utsikt over Ishavskatedralen. Sentralt for nordlyssafari, Polaria og bysentrum. Godt vedlikeholdt helårsanlegg.', 'parking', '{"https://images.unsplash.com/photo-1506521781263-d8422e82f27a?w=800&h=600&fit=crop","https://images.unsplash.com/photo-1593941707882-a5bba14938c7?w=800&h=600&fit=crop"}', 'Tromsø', 'Troms og Finnmark', 'Havnegata 5', 69.6496, 18.9553, 130, 'time', 4.6, 76, '{"lighting","security_camera","gated"}', null, 15, '{"popular","featured"}', 'Lars Nordlys', 'https://images.unsplash.com/photo-1506794778202-cad84cf45f1d?w=100&h=100&fit=crop&facepad=2', 93, 'innen 2 timer', 2022, 2),
('c9', 'Sognefjorden Panorama', 'Campingplass ved verdens lengste fjord. Spektakulær utsikt over Sognefjorden fra terrasserte plasser. Nærhet til Flåmsbana og Nærøyfjorden.', 'camping', '{"https://images.unsplash.com/photo-1478827536114-da961b7f86d2?w=800&h=600&fit=crop","https://images.unsplash.com/photo-1504280390367-361c6d9f38f4?w=800&h=600&fit=crop"}', 'Balestrand', 'Vestland', 'Fjordvegen 22', 61.2094, 6.5314, 370, 'natt', 4.8, 198, '{"electricity","water","toilets","showers","wifi","lake_access","mountain_view","waste_disposal"}', 14, 30, '{"popular","featured","available_today"}', 'Kristin Sogndal', 'https://images.unsplash.com/photo-1534528741775-53994a69daeb?w=100&h=100&fit=crop&facepad=2', 99, 'innen 30 min', 2020, 3),
('p10', 'Kristiansand Kvadraturen', 'Trygg parkering i hjertet av Kristiansand sentrum. Gåavstand til Dyreparken, Fiskebrygga og Markens gate. Perfekt for dagsturer til Sørlandet.', 'parking', '{"https://images.unsplash.com/photo-1573348722427-f1d6819fdf98?w=800&h=600&fit=crop","https://images.unsplash.com/photo-1486006920555-c77dcf18193c?w=800&h=600&fit=crop"}', 'Kristiansand', 'Agder', 'Markens gate 15', 58.1462, 7.9956, 110, 'time', 4.4, 63, '{"lighting","covered","security_camera"}', null, 10, '{"available_today","featured"}', 'Julie Sørland', 'https://images.unsplash.com/photo-1544005313-94ddf0286df2?w=100&h=100&fit=crop&facepad=2', 89, 'innen 3 timer', 2023, 2),
